// src/pages/MarketNewsPage.js

import React, { useState } from "react";
import axios from "axios";

function MarketNewsPage() {
  const [news, setNews] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const fetchNews = async () => {
    setLoading(true);
    setError("");
    setNews(null);

    try {
      const res = await axios.get("/api/market-news");
      console.log("NEWS DATA", res.data);
      setNews(res.data);
    } catch (err) {
      console.error(err.response?.data || err.message);
      setError(err.response?.data?.error || "Failed to fetch news.");
    } finally {
      setLoading(false);
    }
  };

  const pageStyle = {
    maxWidth: "700px",
    margin: "50px auto",
    fontFamily: "Arial, sans-serif",
  };

  const headingStyle = {
    fontSize: "24px",
    fontWeight: "bold",
    marginBottom: "20px",
    textAlign: "center",
  };

  const buttonStyle = {
    display: "inline-block",
    padding: "10px 20px",
    fontSize: "16px",
    backgroundColor: "#28a745",
    color: "#fff",
    border: "none",
    borderRadius: "4px",
    cursor: "pointer",
  };

  const resultStyle = {
    marginTop: "20px",
    padding: "15px",
    backgroundColor: "#f4f4f4",
    borderRadius: "4px",
    whiteSpace: "pre-wrap",
  };

  const errorStyle = {
    color: "red",
    marginTop: "10px",
  };

  return (
    <div style={pageStyle}>
      <h1 style={headingStyle}>Market News</h1>

      <button style={buttonStyle} onClick={fetchNews} disabled={loading}>
        {loading ? "Fetching..." : "Fetch Latest Market News"}
      </button>

      {error && <div style={errorStyle}>{error}</div>}

      {news && (
        <div style={resultStyle}>
          <h3>Headline:</h3>
          <p>{news.headline}</p>

          <h3>Summary:</h3>
          <p>{news.summary}</p>

          <h3>Sentiment:</h3>
          <p>
            {news.sentiment} (Score: {news.score?.toFixed(3)})
          </p>
        </div>
      )}
    </div>
  );
}

export default MarketNewsPage;
